use std::io::stdin;

fn main() {
    let mut input = String::new();
    stdin().read_line(&mut input).expect("error");

    let size = 'z' as i32 - 'a' as i32 + 1;

    let mut sum = 0;
    let mut old_char = 'a';

    for c in input.trim().chars() {
        sum += std::cmp::min(
            (old_char as i32 - c as i32).abs(),
            size - (old_char as i32 - c as i32).abs(),
        );
        old_char = c;
    }
    println!("{}", sum);
}
